Rule.Source:
  import sailpoint.object.Application;
  import sailpoint.object.Custom;
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.tools.Util;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import java.util.List;
  import java.util.ArrayList;

  // Helper method to find existing accounts (matches Prod logic)
  public List getIdentityAppLinks(Identity identity, String appName){
    QueryOptions qo = new QueryOptions();
    Filter filter = Filter.ignoreCase(Filter.and(Filter.eq("application.name", appName), Filter.eq("identity.name",identity.getName())));
    qo.addFilter(filter);
    List links = context.getObjects(Link.class, qo);
    return links;
  }

  // --- Main Logic ---
  if(identity != null && !identity.isInactive()){

    String type = identity.getType();   
    String businessUnit = identity.getAttribute("businessUnit");
    String samAccountName = identity.getAttribute("samAccountName");

    // CORRECTED: Updated to "employeeClass" to match your ObjectConfig XML
    String emplClass = identity.getAttribute("employeeClass"); 

    // Pre-requisites: Must have SAM Account AND be Employee (Matches Prod)
    if(Util.isNotNullOrEmpty(samAccountName) && Util.nullSafeCaseInsensitiveEq(type, "employee")){

      boolean isEligible = false;
      String customObjName = "Ascension-Custom-Gsuite";

      // Load Dynamic Configuration (The New Requirement)
      Custom configObj = context.getObjectByName(Custom.class, customObjName);

      if (configObj != null) {
        // Util.asList handles single Strings, Lists, or Nulls safely
        List validBUs = Util.asList(configObj.get("businessUnitsForAutoProvisioning"));
        List validClasses = Util.asList(configObj.get("emplClassForAutoProvisioning"));
        
        // Helper flag for robust matching
        boolean matchFound = false;

        // Check 1: Business Unit Match (Case Insensitive Loop)
        if (businessUnit != null && Util.nullSafeSize(validBUs) > 0) {
            for(Object item : validBUs) {
                if(item != null && String.valueOf(item).equalsIgnoreCase(businessUnit)) {
                    matchFound = true;
                    break;
                }
            }
        }
        
        // Check 2: Employee Class Match (OR condition - only if BU match didn't happen)
        if (!matchFound && emplClass != null && Util.nullSafeSize(validClasses) > 0) {
             for(Object item : validClasses) {
                if(item != null && String.valueOf(item).equalsIgnoreCase(emplClass)) {
                    matchFound = true;
                    break;
                }
            }
        }
        
        if (matchFound) {
            isEligible = true;
        }

      } else {
        // Log error if config is missing, but do not crash
        log.error("Ascension-Rule-IdentitySelector-VPN: Custom Object '" + customObjName + "' not found. Access denied.");
      }

      // Final Assignment Check (Matches Prod)
      if (isEligible) {
        // Prod only checks for "AD-DS" links
        List links = getIdentityAppLinks(identity, "AD-DS");   
        if (links != null && !links.isEmpty()) {            
          return true;
        }
      }
    }
  }
  return false;
